        <header class="meow-header" id="meow-toggle-header">
            <div class="serial"></div>
            <div class="time"></div>
            <div class="expand-button"><span id="expand-button-text">叩响塔门…</span></div>
        </header>

        <div class="meow-collapsible" id="meow-collapsible-content">
            <div class="meow-content">
                <div class="content-wrapper">
                    <div class="scene">
                        <span class="scene-label">𝓢𝓬𝓮𝓷𝓪𝓻𝓲𝓸</span>
                        <div class="scene-content"></div>
                    </div>
